def token_autenticacao():
    # Chama a API de login uma única vez por execução
    import requests
    resp = requests.post("https://api.exemplo.com/auth", json={
        "user": "teste@exemplo.com", "password": "senha123"
    })
    return resp.json()["access_token"]


def test_endpoint_protegido(token_autenticacao):
    import requests
    headers = {"Authorization": f"Bearer {token_autenticacao}"}
    resp = requests.get("https://api.exemplo.com/users", headers=headers)
    assert resp.status_code == 200
